INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("トゥインクルウィッシュ", "人助けが大好き！　前向き格闘娘", 8, 16, "人助け、応援", 2, 155, 0, "A", "獣人族", 100101, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 27, "東山奈央", 44, "ヒヨリ");
