INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("悪魔偽王国軍（ディアボロス）", "プリン大好きゴースト娘", 1, 14, "プリンを食べること", 7, 130, 0, "B", "魔族", 100701, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 23, "雨宮天", 32, "ミヤコ");
