INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("トワイライトキャラバン", "前世を信じる中二病患者、「疾風の冥姫」", 7, 17, "小説執筆", 13, 159, 0, "A", "魔族", 100901, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 5, "髙野麻美", 45, "アンナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("自警団（カォン）", "マホマホ王国のプリンセス", 9, 16, "空想、ぬいぐるみ集め", 10, 155, 0, "O", "獣人族", 101001, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 22, "内田真礼", 42, "マホ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ラビリンス", "人懐っこくてマシンガントークな妹系少女", 8, 15, "お裁縫", 3, 156, 0, "A", "ヒューマン", 101101, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 25, "阿澄佳奈", 44, "リノ");
