INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ルーセント学院", "天真爛漫で人気者のカリスマモデル", 4, 17, "ファッション", 14, 167, 0, "O", "魔族", 101601, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 10, "上坂すみれ", 48, "スズナ");
