INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ルーセント学院", "多くの男性を魅了する無垢な女教師", 8, 23, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 14, 162, 0, "B", "魔族", 101801, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 14, "伊藤静", 52, "イオ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("リトルリリカル", "お歌もにんじんも、ウサギさんも大好き♪", 4, 10, "かわいいもの集め", 5, 117, 0, "O", "獣人族", 102001, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 3, "日高里菜", 21, "ミミ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("サレンディア救護院", "泣き虫で臆病な守ってあげたい女の子", 6, 12, "観劇、おままごと", 9, 150, 0, "B", "ヒューマン", 102101, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 9, "植田佳奈", 40, "クルミ");
