INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("牧場（エリザベスパーク）", "読書が趣味の病弱少女", 11, 14, "読書、お散歩", 11, 153, 0, "A", "獣人族", 103801, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 3, "小清水亜美", 40, "シオリ");
