INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("メルクリウス財団", "弱きを助け強きをくじく猫娘", 3, 19, "猫とたわむれること", 12, 158, 0, "AB", "獣人族", 107901, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 1, "沼倉愛美", 48, "タマキ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("メルクリウス財団", "仕事も私事も効率優先な傭兵少女", 11, 20, "傭兵などのアルバイト", 12, 163, 0, "O", "ヒューマン", 108001, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 11, "田所あずさ", 49, "ミフユ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("悪魔偽王国軍（ディアボロス）", "占いが得意な霊能少女", 12, 18, "占い", 7, 157, 0, "AB", "魔族", 108101, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 22, "大坪由佳", 42, "シノブ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("悪魔偽王国軍（ディアボロス）", "プリン大好きゴースト娘", 1, 14, "プリンを食べること", 7, 130, 0, "B", "魔族", 108201, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 23, "雨宮天", 32, "ミヤコ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ルーセント学院", "ちょっとおませな恋に恋する女の子", 1, 11, "ファッション誌鑑賞、コスメ集め", 14, 120, 0, "A", "魔族", 108301, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 3, "久野美咲", 22, "ミサキ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("カルミナ", "人々を守るために歌う、唱喚士の少女", 6, 17, "各種楽器", 4, 163, 0, "O", "ヒューマン", 108401, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 3, "福原綾香", 46, "チカ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("サレンディア救護院", "泣き虫で臆病な守ってあげたい女の子", 6, 12, "観劇、おままごと", 9, 150, 0, "B", "ヒューマン", 108501, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 9, "植田佳奈", 40, "クルミ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("サレンディア救護院", "ぷうきちといつも一緒！", 5, 14, "屋内でできる遊び", 9, 148, 0, "B", "ヒューマン", 108601, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 10, "芹澤優", 38, "アヤネ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("トゥインクルウィッシュ", "人助けが大好き！　前向き格闘娘", 8, 16, "人助け、応援", 2, 155, 0, "A", "獣人族", 108701, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 27, "東山奈央", 44, "ヒヨリ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("トゥインクルウィッシュ", "戦闘のサポートが得意な、心優しい少女", 4, 17, "料理、人間観察", 2, 158, 0, "O", "ヒューマン", 108801, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 5, "種田梨沙", 47, "ユイ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("トゥインクルウィッシュ", "クールで何事にも真っ直ぐな剣士", 1, 18, "読書、乗馬、お茶", 2, 163, 0, "B", "魔族", 108901, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 12, "早見沙織", 46, "レイ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("トワイライトキャラバン", "運命の相手に一途すぎる乙女", 7, 16, "実験、裁縫、料理", 13, 154, 0, "B", "魔族", 109001, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 30, "橋本ちなみ", 43, "エリコ（バレンタイン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ラビリンス", "お姉ちゃんがお世話してあげるからねっ！", 10, 18, "家事全般", 3, 168, 0, "O", "ヒューマン", 109101, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 24, "生天目仁美", 54, "シズル（バレンタイン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("？？？", "英霊と契約を結んだマナリアの天才王女", 12, 17, "読書", "", 156, 0, "AB", "ヒューマン", 109201, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", 1, "日笠陽子", 55, "アン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("？？？", "マナリア魔法学院の新入生", 2, 16, "食べること、眠ること", "", 144, 0, "O", "ヒューマン", 109301, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", 4, "こやまきみこ", 45, "ルゥ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("？？？", "人を超越した力を有す心優しい竜姫", 11, 17, "ピアノ", "", 167, 0, "B", "半人半竜", 109401, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", 3, "福原綾香", 67, "グレア");
